package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.tuple;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Set;

import org.junit.jupiter.api.Test;

class JoinRegionIdentityTest {

	@Test
	void identityIsCanonicalAcrossFactorAndDependencyCollectionOrder() {
		JoinRegion first = new JoinRegion(
				List.of(new JoinFactor(2, 30), new JoinFactor(0, 10), new JoinFactor(1, 20)),
				List.of(new JoinDependency(2, linkedSet(1, 0)), new JoinDependency(1, Set.of(0))));
		JoinRegion reordered = new JoinRegion(
				List.of(new JoinFactor(1, 20), new JoinFactor(0, 10), new JoinFactor(2, 30)),
				List.of(new JoinDependency(1, Set.of(0)), new JoinDependency(2, linkedSet(0, 1))));

		Object firstIdentity = identity(first);
		Object reorderedIdentity = identity(reordered);

		assertThat(firstIdentity.getClass()).isEqualTo(reorderedIdentity.getClass());
		assertThat(firstIdentity).isEqualTo(reorderedIdentity);
		assertThat(firstIdentity.hashCode()).isEqualTo(reorderedIdentity.hashCode());
	}

	@Test
	void identityIncludesTheDependencyGraph() {
		List<JoinFactor> factors = List.of(new JoinFactor(0, 10), new JoinFactor(1, 20),
				new JoinFactor(2, 30));
		JoinRegion dependsOnFirst = new JoinRegion(factors, List.of(new JoinDependency(2, Set.of(0))));
		JoinRegion dependsOnSecond = new JoinRegion(factors, List.of(new JoinDependency(2, Set.of(1))));

		assertThat(identity(dependsOnFirst)).isNotEqualTo(identity(dependsOnSecond));
	}

	@Test
	void identityPreservesRepeatedGroupOccurrences() {
		List<JoinFactor> repeatedGroupFactors = List.of(new JoinFactor(10, 7), new JoinFactor(11, 7),
				new JoinFactor(12, 8));
		JoinRegion dependsOnFirstOccurrence = new JoinRegion(repeatedGroupFactors,
				List.of(new JoinDependency(12, Set.of(10))));
		JoinRegion dependsOnSecondOccurrence = new JoinRegion(repeatedGroupFactors,
				List.of(new JoinDependency(12, Set.of(11))));
		JoinRegion differentSecondGroup = new JoinRegion(
				List.of(new JoinFactor(10, 7), new JoinFactor(11, 9), new JoinFactor(12, 8)),
				List.of(new JoinDependency(12, Set.of(10))));

		assertThat(dependsOnFirstOccurrence.factors())
				.extracting(JoinFactor::occurrenceId, JoinFactor::groupId)
				.containsExactly(tuple(10, 7), tuple(11, 7), tuple(12, 8));
		assertThat(identity(dependsOnFirstOccurrence)).isNotEqualTo(identity(dependsOnSecondOccurrence));
		assertThat(identity(dependsOnFirstOccurrence)).isNotEqualTo(identity(differentSecondGroup));
	}

	private static Object identity(JoinRegion region) {
		try {
			Method identityMethod = JoinRegion.class.getMethod("identity");
			Class<?> identityType = identityMethod.getReturnType();
			assertThat(identityType).isNotEqualTo(String.class);
			assertThat(identityType.getEnclosingClass()).isEqualTo(JoinRegion.class);
			return identityMethod.invoke(region);
		} catch (NoSuchMethodException e) {
			throw new AssertionError("JoinRegion must expose a typed identity() value", e);
		} catch (IllegalAccessException | InvocationTargetException e) {
			throw new AssertionError("JoinRegion identity() must be accessible", e);
		}
	}

	private static Set<Integer> linkedSet(int... values) {
		LinkedHashSet<Integer> result = new LinkedHashSet<>();
		for (int value : values) {
			result.add(value);
		}
		return result;
	}
}
